import React, { useRef, useEffect, useCallback, useState } from 'react';

const FIRST_CHUNK   = 2  * 1024 * 1024;   // 2 MB  — fast first frame
const CHUNK         = 20 * 1024 * 1024;   // 20 MB — subsequent chunks
const PREFETCH      = 2;                   // parallel fetches ahead
const BUF_AHEAD_S   = 30;
const BUF_BEHIND_S  = 10;
const DRIFT_S       = 0.08;
const SYNC_MS       = 500;
const MAX_RETRY     = 3;
const RETRY_BASE_MS = 500;
const MIME          = 'video/mp4; codecs="avc1.42E01E,mp4a.40.2"';

const MSE_CAPABLE = typeof MediaSource !== 'undefined' && MediaSource.isTypeSupported(MIME);

const sleep = ms => new Promise(r => setTimeout(r, ms));

// ── Probe: Range support + fMP4 detection via moof/mvex box scan ─────────────
// Plain MP4 and fMP4 both start with 'ftyp' — the only reliable distinction is
// the presence of 'moof' (fragment) or 'mvex' (movie extends) boxes.
// We scan the first 64 KB which always contains the full 'moov' of a faststart
// fMP4, and look for 'moof' or 'mvex' box type signatures.
async function probeStream(url) {
  try {
    const res = await fetch(url, {
      headers: { Range: 'bytes=0-65535' },
      signal: AbortSignal.timeout(8000),
    });
    if (res.status !== 206) return false;
    const buf   = await res.arrayBuffer();
    const bytes = new Uint8Array(buf);
    // Walk top-level boxes looking for 'moof' or 'mvex'
    let offset = 0;
    while (offset + 8 <= bytes.length) {
      const size = (bytes[offset] << 24) | (bytes[offset+1] << 16) |
                   (bytes[offset+2] << 8)  |  bytes[offset+3];
      const type = String.fromCharCode(bytes[offset+4], bytes[offset+5],
                                       bytes[offset+6], bytes[offset+7]);
      if (type === 'moof' || type === 'mvex') return true;
      if (size < 8) break;   // corrupt box
      offset += size;
    }
    return false;
  } catch { return false; }
}

async function fetchChunk(url, start, end, signal) {
  for (let i = 0; i <= MAX_RETRY; i++) {
    try {
      const res = await fetch(url, { headers: { Range: `bytes=${start}-${end}` }, signal });
      if (!res.ok && res.status !== 206) throw new Error(`HTTP ${res.status}`);
      return await res.arrayBuffer();
    } catch (e) {
      if (signal.aborted || i === MAX_RETRY) throw e;
      await sleep(RETRY_BASE_MS * 2 ** i);
    }
  }
}

async function getSize(url, signal) {
  try {
    const res = await fetch(url, { method: 'HEAD', signal });
    return parseInt(res.headers.get('content-length') || '0', 10);
  } catch { return 0; }
}

// ── MSE Engine ────────────────────────────────────────────────────────────────
class Engine {
  constructor(video, src) {
    this.video      = video;
    this.src        = src;
    this.ms         = new MediaSource();
    this.sb         = null;
    this.total      = 0;
    this.next       = 0;
    this.inflight   = 0;
    this.queue      = [];
    this.eos        = false;
    this.dead       = false;
    this.fired      = false;
    this.ac         = new AbortController();
    this.ready      = new Promise(r => { this._resolve = r; });
    this._url       = URL.createObjectURL(this.ms);
  }

  start() {
    this.video.src = this._url;
    this.ms.addEventListener('sourceopen', () => this._open(), { once: true });
    return this.ready;
  }

  async _open() {
    this.sb = this.ms.addSourceBuffer(MIME);
    this.sb.mode = 'sequence';
    this.sb.addEventListener('updateend', () => this._drain());
    this.total = await getSize(this.src, this.ac.signal);
    this._pump();
  }

  _ahead() {
    const v = this.video, ct = v.currentTime;
    for (let i = 0; i < v.buffered.length; i++)
      if (v.buffered.start(i) <= ct + 0.5 && v.buffered.end(i) > ct)
        return v.buffered.end(i) - ct;
    return 0;
  }

  _done() { return this.total > 0 && this.next >= this.total; }

  _pump() {
    if (this.dead || this._done() || this._ahead() >= BUF_AHEAD_S) return;
    while (this.inflight < PREFETCH && !this._done()) this._fetch();
  }

  async _fetch() {
    const start = this.next;
    const size  = this.fired ? CHUNK : FIRST_CHUNK;
    const end   = this.total ? Math.min(start + size - 1, this.total - 1) : start + size - 1;
    this.next = end + 1;
    this.inflight++;
    try {
      const buf = await fetchChunk(this.src, start, end, this.ac.signal);
      if (!this.dead) { this.queue.push(buf); this._drain(); }
    } catch (e) {
      if (!this.dead) console.warn('[MSE] fetch error', e);
    } finally {
      this.inflight--;
      if (!this.dead) this._pump();
    }
  }

  _drain() {
    if (!this.sb || this.sb.updating || !this.queue.length) return;
    try { this.sb.appendBuffer(this.queue.shift()); } catch (e) {
      console.warn('[MSE] appendBuffer', e); return;
    }
    if (!this.fired) { this.fired = true; this._resolve(); }
    if (this._done() && !this.queue.length && !this.eos) {
      this.sb.addEventListener('updateend', () => {
        if (!this.eos && this.ms.readyState === 'open') {
          this.eos = true; try { this.ms.endOfStream(); } catch {}
        }
      }, { once: true });
    }
  }

  _evict() {
    const v = this.video;
    if (!this.sb || this.sb.updating || !v.buffered.length) return;
    const end = v.currentTime - BUF_BEHIND_S;
    if (end > 0) try { this.sb.remove(0, end); } catch {}
  }

  onTime()  { this._evict(); this._pump(); }
  onSeek()  {
    if (!this.total) return;
    const v = this.video;
    this.next = Math.floor((v.currentTime / (v.duration || 1)) * this.total / CHUNK) * CHUNK;
    this.inflight = 0; this.queue = [];
    this._pump();
  }

  destroy() {
    this.dead = true; this.sb = null;
    this.ac.abort();
    try { if (this.ms.readyState === 'open') this.ms.endOfStream(); } catch {}
    URL.revokeObjectURL(this._url);
  }
}

// ── Component ─────────────────────────────────────────────────────────────────
const VideoAudioPlayer = ({ src, id, activeAudioId, onVisibilityChange }) => {
  const videoRef = useRef(null);
  const audioRef = useRef(null);
  const boxRef   = useRef(null);
  const engRef   = useRef(null);
  const syncRef  = useRef(null);
  // null=probing  true=MSE  false=native
  const [mode, setMode] = useState(null);
  const isActive = activeAudioId === id;
  const audioSrc = src.replace(/\.(mp4|webm)(\?.*)?$/i, '.mp3$2');

  // Probe once per src
  useEffect(() => {
    if (!MSE_CAPABLE) { setMode(false); return; }
    let live = true;
    probeStream(src).then(ok => { if (live) { console.log(`[VAP] ${ok ? 'MSE' : 'native'} <- ${src}`); setMode(ok); } });
    return () => { live = false; };
  }, [src]);

  // Sync helpers
  const startSync = useCallback(() => {
    clearInterval(syncRef.current);
    syncRef.current = setInterval(() => {
      const v = videoRef.current, a = audioRef.current;
      if (!v || !a || v.paused || a.paused) return;
      if (Math.abs(v.currentTime - a.currentTime) > DRIFT_S) a.currentTime = v.currentTime;
    }, SYNC_MS);
  }, []);
  const stopSync = useCallback(() => clearInterval(syncRef.current), []);

  // Bootstrap video once mode is known
  useEffect(() => {
    if (mode === null) return;
    const video = videoRef.current;
    if (!video) return;

    if (mode) {
      const eng = new Engine(video, src);
      engRef.current = eng;

      // If MSE errors mid-stream → fallback to native
      const onErr = () => {
        eng.destroy(); engRef.current = null;
        setMode(false);
      };
      video.addEventListener('error', onErr, { once: true });

      eng.start().then(() => {
        const a = audioRef.current;
        if (a && isActive) { a.currentTime = video.currentTime; a.play().catch(() => {}); }
        video.play().catch(() => {});
      });

      const onTime = () => eng.onTime();
      const onSeek = () => eng.onSeek();
      video.addEventListener('timeupdate', onTime);
      video.addEventListener('seeking',    onSeek);
      return () => {
        video.removeEventListener('error',      onErr);
        video.removeEventListener('timeupdate', onTime);
        video.removeEventListener('seeking',    onSeek);
        eng.destroy(); engRef.current = null;
      };
    } else {
      video.src = src;
      video.play().catch(() => {});
      return () => { video.src = ''; };
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, src]);

  // Audio control
  useEffect(() => {
    const a = audioRef.current, v = videoRef.current;
    if (!a || !v) return;
